+import { mkdir, readFile, writeFile } from 'node:fs/promises'
+import { dirname, resolve } from 'pathe'
+import type { DurationObservation } from './duration-smoothing'
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const raw = JSON.parse(await readFile(resolve(root, path), 'utf8'))
+    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null
+    const expiry = Date.now() - ttl
+    const history: DurationHistory = {}
+    for (const [file, value] of Object.entries(raw)) {
+      const observations = typeof value === 'number'
+        ? [{ duration: value, recordedAt: 0 }]
+        : value && typeof value === 'object' && 'observations' in value
+          ? (value as { observations: unknown }).observations
+          : value && typeof value === 'object' && 'duration' in value
+            ? [value]
+            : null
+      if (!Array.isArray(observations) || observations.some(item => !item || typeof item !== 'object' || !Number.isFinite((item as DurationObservation).duration) || !Number.isFinite((item as DurationObservation).recordedAt))) return null
+      history[file] = (observations as DurationObservation[]).filter(item => !ttl || item.recordedAt === 0 || item.recordedAt >= expiry)
+    }
+    return history
+  }
+  catch {
+    return null
+  }
+}
+
+export async function writeDurationHistory(root: string, path: string, history: DurationHistory, maxRuns: number): Promise<void> {
+  const output: Record<string, unknown> = {}
+  for (const [file, observations] of Object.entries(history)) {
+    const recent = [...observations].sort((a, b) => b.recordedAt - a.recordedAt).slice(0, maxRuns)
+    if (recent.length) output[file] = maxRuns === 1 ? recent[0] : { observations: recent }
+  }
+  const target = resolve(root, path)
+  await mkdir(dirname(target), { recursive: true })
+  await writeFile(target, `${JSON.stringify(output, null, 2)}\
`)
